script.body:
param([string]$RepoPath = '.', [bool]$All = $false)
Push-Location $RepoPath
try {
    $args = @('branch')
    if ($All) { $args += '-a' }
    $args += '--format=%(if)%(HEAD)%(then)*%(else) %(end)%(refname:short)|%(objectname:short)|%(committerdate:relative)'
    & git @args | ForEach-Object {
        $parts = $_ -split '\|'
        [PSCustomObject]@{
            Current = if ($parts[0] -match '^\*') { '*' } else { '' }
            Branch = $parts[0].TrimStart('* ')
            Commit = $parts[1]
            LastCommit = $parts[2]
        }
    } | Format-Table -AutoSize
} finally {
    Pop-Location
}
